 88→pub async fn create_vehicle(
 89→    State(state): State<AppState>,
 90→    headers: HeaderMap,
 91→    Json(req): Json<CreateVehicleRequest>,
 92→) -> Result<(axum::http::StatusCode, Json<MaskedVehicle>), AppError> {
 93→    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
