110→    let plate_hash = hash_field(&req.license_plate);
111→
112→    let vehicle = Vehicle {
113→        id: uuid::Uuid::new_v4().to_string(),
114→        vin_encrypted, vin_hash, license_plate_encrypted: plate_encrypted, license_plate_hash: plate_hash,
115→        make: req.make.clone(), model: req.model.clone(),
116→        trim_level: req.trim_level.clone().unwrap_or_default(),
117→        store_id: req.store_id.clone(),
118→        mileage_miles: req.mileage_miles.unwrap_or(0),
119→        fuel_or_battery_pct: req.fuel_or_battery_pct.unwrap_or(100.0),
120→        status: "available".to_string(),
121→        maintenance_due: req.maintenance_due.clone(),
122→        inspection_due: req.inspection_due.clone(),
123→        insurance_expiry: req.insurance_expiry.clone(),
124→        version: 1,
125→    };
126→
127→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
128→    crate::repositories::vehicles::create(&db, &vehicle)
129→        .map_err(|e| AppError::Internal(e.to_string()))?;
130→
131→    let _ = crate::audit::chain::append_audit_log(
132→        &db, &claims.user_id, &claims.username, "CREATE", "vehicle", &vehicle.id,
133→        &serde_json::json!({"make": req.make, "model": req.model, "store_id": req.store_id}),
134→    );
135→
136→    Ok((axum::http::StatusCode::CREATED, Json(MaskedVehicle {
137→        id: vehicle.id, vin: masking::mask_vin(&req.vin),
138→        license_plate: masking::mask_license_plate(&req.license_plate),
139→        make: req.make, model: req.model, trim_level: req.trim_level.unwrap_or_default(),
140→        store_id: req.store_id, mileage_miles: req.mileage_miles.unwrap_or(0),
141→        fuel_or_battery_pct: req.fuel_or_battery_pct.unwrap_or(100.0),
142→        status: "available".to_string(), maintenance_due: req.maintenance_due,
143→        inspection_due: req.inspection_due, insurance_expiry: req.insurance_expiry,
144→    })))
