147→pub async fn update_status(
148→    State(state): State<AppState>,
149→    headers: HeaderMap,
150→    Path(id): Path<String>,
151→    Json(req): Json<StatusTransitionRequest>,
152→) -> Result<Json<serde_json::Value>, AppError> {
153→    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
154→    require_role(&claims, &UserRole::MerchantStaff)?;
155→    require_csrf_with_state(&headers, &claims, &state)?;
156→
157→    let new_status = VehicleStatus::from_str(&req.status)
158→        .ok_or_else(|| AppError::Validation(format!("Invalid status: {}", req.status)))?;
159→
160→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
161→    let vehicle = crate::repositories::vehicles::find_by_id(&db, &id)
162→        .map_err(|e| AppError::Internal(e.to_string()))?
163→        .ok_or_else(|| AppError::NotFound("Vehicle not found".to_string()))?;
164→
165→    // Store isolation
166→    if let Some(ref user_store) = claims.store_id {
167→        let role = UserRole::from_str(&claims.role).unwrap_or(UserRole::Customer);
168→        if !matches!(role, UserRole::PlatformOps | UserRole::Administrator) && vehicle.store_id != *user_store {
169→            return Err(AppError::Forbidden("Access denied".to_string()));
170→        }
171→    }
172→
173→    let current = VehicleStatus::from_str(&vehicle.status)
174→        .ok_or_else(|| AppError::Internal("Invalid current status".to_string()))?;
175→
176→    if !current.can_transition_to(&new_status) {
177→        return Err(AppError::Validation(format!(
178→            "Cannot transition from {} to {}", current.as_str(), new_status.as_str()
179→        )));
180→    }
181→
182→    if current.requires_admin(&new_status) {
183→        require_role(&claims, &UserRole::Administrator)?;
184→    }
185→
186→    let updated = crate::repositories::vehicles::update_status(&db, &id, new_status.as_str(), vehicle.version)
187→        .map_err(|e| AppError::Internal(e.to_string()))?;
188→
189→    if !updated {
190→        return Err(AppError::Conflict("Version conflict, please retry".to_string()));
191→    }
192→
193→    let _ = crate::audit::chain::append_audit_log(
194→        &db, &claims.user_id, &claims.username, "STATUS_CHANGE", "vehicle", &id,
195→        &serde_json::json!({"from": current.as_str(), "to": new_status.as_str()}),
196→    );
197→
198→    Ok(Json(serde_json::json!({"message": "Status updated", "status": new_status.as_str()})))
199→}
