use axum::http::HeaderMap;
use axum::Json;
use crate::app::state::AppState;
use crate::errors::AppError;
use crate::handlers::auth::*;
use crate::models::*;

pub async fn list_stores(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Json<serde_json::Value>, AppError> {
    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;

    let role = UserRole::from_str(&claims.role).unwrap_or(UserRole::Customer);
    let stores = if matches!(role, UserRole::PlatformOps | UserRole::Administrator) {
        crate::repositories::stores::find_all(&db)
    } else {
        // Non-elevated users only see their own store
        match &claims.store_id {
            Some(sid) => {
                match crate::repositories::stores::find_by_id(&db, sid)? {
                    Some(s) => Ok(vec![s]),
                    None => Ok(vec![]),
                }
            }
            None => Ok(vec![]),
        }
    }.map_err(|e| AppError::Internal(e.to_string()))?;

    Ok(Json(serde_json::json!({"stores": stores})))
}
"}

