{"file_path": "/Users/mac/TASK-w2t76/repo/frontend/src/components/upload_form.rs", "content": "use leptos::*;
use crate::state::auth::AuthState;

/// Reusable upload form component for vehicle photos.
/// Performs client-side validation (type, size) then POSTs multipart to /api/uploads.
#[component]
pub fn UploadForm(
    #[prop(optional)] vehicle_id: Option<String>,
    #[prop(optional)] on_success: Option<Box<dyn Fn()>>,
) -> impl IntoView {
    let status = create_rw_signal(Option::<(bool, String)>::None);

    let vid = vehicle_id.clone();
    let on_file_change = move |ev: leptos::ev::Event| {
        let input: web_sys::HtmlInputElement = event_target(&ev);
        if let Some(files) = input.files() {
            if let Some(file) = files.get(0) {
                let name = file.name();
                let size = file.size() as usize;
                if size > 10 * 1024 * 1024 {
                    status.set(Some((false, "File exceeds 10 MB limit".into())));
                    return;
                }
                let ext = name.rsplit('.').next().unwrap_or("").to_lowercase();
                if ext != "jpg" && ext != "jpeg" && ext != "png" {
                    status.set(Some((false, "Only JPEG and PNG files are accepted".into())));
                    return;
                }

                let vehicle = vid.clone();
                spawn_local(async move {
                    let form_data = web_sys::FormData::new().unwrap();
                    let _ = form_data.append_with_blob("file", &file);
                    if let Some(ref v) = vehicle {
                        let _ = form_data.append_with_str("vehicle_id", v);
                    }
                    match crate::api::client::api_upload("/uploads", &form_data).await {
                        Ok((201, _)) => {
                            status.set(Some((true, format!("'{}' uploaded successfully", name))));
                        }
                        Ok((status_code, json)) => {
                            let msg = serde_wasm_bindgen::from_value::<serde_json::Value>(json)
                                .ok()
                                .and_then(|v| v.get("error").and_then(|e| e.get("message")).and_then(|m| m.as_str()).map(|s| s.to_string()))
                                .unwrap_or(format!("Upload failed (HTTP {})", status_code));
                            status.set(Some((false, msg)));
                        }
                        Err(e) => status.set(Some((false, e))),
                    }
                });
            }
        }
    };

    view! {
        <div class="form-group">
            <label>"Upload Photo (JPEG/PNG, max 10 MB)"</label>
            <input type="file" accept="image/jpeg,image/png" on:change=on_file_change />
        </div>
        <Show when=move || status.get().is_some()>
            {move || {
                let (ok, msg) = status.get().unwrap();
                view! {
                    <p style=format!("font-size: 0.875rem; color: {};", if ok { "#166534" } else { "#991b1b" })>
                        {msg}
                    </p>
                }
            }}
        </Show>
    }
}
"}

