    let code_hash = {
        use sha2::{Sha256, Digest};
        hex::encode(Sha256::digest(code.as_bytes()))
    };
    let rc = fleetreserve_backend::models::RecoveryCode {
        id: "rc-reset-1".into(),
        user_id: "reset-user-1".into(),
        code_hash: code_hash.clone(),
        issued_by: "admin".into(),
        issued_at: chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string(),
        expires_at: (chrono::Utc::now() + chrono::Duration::minutes(30)).format("%Y-%m-%d %H:%M:%S").to_string(),
        used: false,
    };
    fleetreserve_backend::repositories::recovery_codes::create(&conn, &rc).unwrap();

